// Test stackalloc with Span<nint> and Span<nuint>

Console.WriteLine($"nint size: {nint.Size} bytes");

// stackalloc Span<nint>
Span<nint> signed = stackalloc nint[4];
signed[0] = 10;
signed[1] = 20;
signed[2] = 30;
signed[3] = nint.MaxValue;

Console.WriteLine("Span<nint> via stackalloc:");
for (int i = 0; i < signed.Length; i++)
    Console.WriteLine($"  [{i}] = {signed[i]}");

// stackalloc Span<nuint>
Span<nuint> unsigned = stackalloc nuint[3];
unsigned[0] = 100;
unsigned[1] = nuint.MaxValue;
unsigned[2] = 0;

Console.WriteLine("Span<nuint> via stackalloc:");
for (int i = 0; i < unsigned.Length; i++)
    Console.WriteLine($"  [{i}] = {unsigned[i]}");

Console.WriteLine("Success — stackalloc with native-sized integers works!");

